#!/usr/bin/env Rscript
# Static, non-Monte-Carlo inventory builder for Task 10.
# It only reads source files and existing result artifacts.

suppressPackageStartupMessages(library(data.table))

root <- normalizePath(".")
out_dir <- file.path(root, "quality_reports")
hash_file <- function(path) unname(tools::md5sum(path))
rel <- function(x) sub(paste0("^", root, "/"), "", normalizePath(x, mustWork = FALSE))

make_row <- function(id, family, script, results, equations, dag, estimand,
                     parameters, n, tt, burn, reps, errors, fe, models,
                     metrics, tags, notes = "", status = "verified_existing_artifacts") {
  script_abs <- file.path(root, script)
  result_abs <- file.path(root, strsplit(results, ";", fixed = TRUE)[[1]])
  result_abs <- result_abs[nzchar(result_abs)]
  result_abs <- result_abs[file.exists(result_abs)]
  data.table(
    inventory_id = id, simulation_family = family, source_script = script,
    source_script_md5 = if (file.exists(script_abs)) hash_file(script_abs) else NA_character_,
    result_file_paths = results,
    result_file_md5 = paste(vapply(result_abs, hash_file, character(1)), collapse = ";"),
    verification_basis = if (file.exists(script_abs) && length(result_abs))
      "directly verified: static source inspection plus existing versioned result artifact" else
      "directly verified source; result artifact absent or not linked",
    equations = equations, causal_dag_description = dag, estimand = estimand,
    parameter_values_or_grid = parameters, N = n, T = tt, burn_in = burn,
    repetitions = reps, error_process = errors, fixed_effects = fe,
    estimated_models = models, metrics = metrics, coverage_tags = tags,
    status = status, notes = notes,
    quantitative_claim_provenance = if (length(result_abs))
      paste0(script, " + ", results) else script
  )
}

