 make_row("diag_sensitivity", "diagnostic: parameter sensitivity", "simulations/diagnostics/diag_sensitivity_params.R", "simulations/diagnostics/results/diag_sensitivity_params_results.csv", "Dynamic dual-role DGP varying rho_Y,gamma_D,gamma_Y and stability.", "Lagged confounding/current collider.", "beta=1.", "reps=200; rho_Y={.3,.5,.7}; stable subset only.", "source", "source", "source", "200", "iid Gaussian.", "unit/time FE.", "FE ADL variants.", "bias and stability summaries.", "dual_role;firewall", "Rows flagged unstable are excluded by source logic; see source/result."),
 make_row("diag_shortT", "diagnostic: short-T / Nickell", "simulations/diagnostics/diag_short_T.R", "simulations/diagnostics/results/diag_short_T_results.csv", "Dynamic dual-role DGP comparing T=10 and 30.", "Lagged confounding/current collider.", "beta=1; finite-T estimator behavior.", "reps=200; T={10,30}; scenarios in source.", "source", "10;30", "source", "200", "iid Gaussian.", "unit/time FE where specified.", "TWFE long; FE ADL; no-FE ADL.", "bias and Nickell-cost comparison.", "dual_role;firewall", "Diagnostic artifact."),
 make_row("diag_timeFE", "diagnostic: time FE in DGP", "simulations/diagnostics/diag_time_fe_in_dgp.R", "simulations/diagnostics/results/diag_time_fe_results.csv", "Dynamic dual-role DGP with time-shock variance sigma_delta.", "Dual-role dynamics plus common time shocks.", "beta=1.", "reps=200; sigma_delta={0,.3,.5,1}; scenarios in source.", "source", "source", "source", "200", "iid Gaussian time shocks and innovations.", "unit/time FE.", "TWFE and FE-ADL variants.", "bias summaries.", "dual_role;time_effects", "Diagnostic artifact.")
)

inventory <- rbindlist(rows, fill = TRUE)
setorder(inventory, inventory_id)

# Static validations: paths/hash existence, required columns, and numeric sanity in
# timing/grid/result CSVs. This intentionally never sources simulation scripts.
required <- c("inventory_id", "source_script", "equations", "causal_dag_description",
  "estimand", "parameter_values_or_grid", "N", "T", "burn_in", "repetitions",
  "error_process", "fixed_effects", "estimated_models", "metrics", "result_file_paths", "status")
stopifnot(identical(required, intersect(required, names(inventory))))
stopifnot(!anyDuplicated(inventory$inventory_id))
stopifnot(all(file.exists(file.path(root, inventory$source_script))))

artifact_rows <- inventory[nzchar(result_file_paths)]
artifact_paths <- unique(unlist(strsplit(artifact_rows$result_file_paths, ";", fixed = TRUE)))
artifact_paths <- artifact_paths[nzchar(artifact_paths)]
missing_artifacts <- artifact_paths[!file.exists(file.path(root, artifact_paths))]
if (length(missing_artifacts)) stop("Missing declared artifacts: ", paste(missing_artifacts, collapse = "; "))

manifest <- rbindlist(lapply(artifact_paths, function(p) {
  x <- file.path(root, p)
  hdr <- if (grepl("\\.csv$", p)) names(fread(x, nrows = 0)) else character()
  checks <- list()
  if (length(hdr)) {
    bounded <- intersect(hdr, c("rho_Z", "rho_Y", "rho_D", "phi", "phi_U", "prob_never", "T_start_frac", "T_end_frac", "R2_within"))
    positive_counts <- intersect(hdr, c("N", "TT", "T", "T_burn", "N_REPS", "n_sims", "n_valid", "sim"))
    nonnegative_counts <- intersect(hdr, c("n_discarded"))
    dates <- hdr[grepl("date", hdr, ignore.case = TRUE)]
    use <- unique(c(bounded, positive_counts, nonnegative_counts, dates))
    if (length(use)) {
      d <- fread(x, select = use, showProgress = FALSE)
      for (nm in bounded) {
        z <- d[[nm]]
        if (is.numeric(z) && any(!is.na(z) & (z < 0 | z > 1))) checks[[length(checks) + 1L]] <- paste0(nm, " outside [0,1]")
      }
      for (nm in positive_counts) {
        z <- d[[nm]]
        if (is.numeric(z) && any(!is.na(z) & z <= 0)) checks[[length(checks) + 1L]] <- paste0(nm, " is non-positive")
      }
      for (nm in nonnegative_counts) {
        z <- d[[nm]]
        if (is.numeric(z) && any(!is.na(z) & z < 0)) checks[[length(checks) + 1L]] <- paste0(nm, " is negative")
      }
      for (nm in dates) {
        z <- as.Date(d[[nm]])
        if (any(is.na(z) & !is.na(d[[nm]])) || any(z > as.Date("2026-07-11"), na.rm = TRUE)) checks[[length(checks) + 1L]] <- paste0(nm, " is invalid or after audit date")
      }
    }
  }
  data.table(path = p, md5 = hash_file(x), bytes = file.info(x)$size,
             csv_header = if (length(hdr)) paste(hdr, collapse = "|") else NA_character_,
             static_validation = if (length(checks)) paste(checks, collapse = "; ") else "PASS")
}))
fwrite(inventory, file.path(out_dir, "simulation_design_inventory.csv"))
fwrite(manifest, file.path(out_dir, "simulation_design_inventory_manifest.csv"))
fwrite(manifest[, .(path, static_validation)], file.path(out_dir, "simulation_design_inventory_validation.csv"))

cat(sprintf("Wrote %d inventory rows and %d artifact-manifest rows.\n", nrow(inventory), nrow(manifest)))
